import re
from datetime import datetime, timedelta

def validate_bing_freshness(search_result: str) -> bool:
    date_pattern = r'published:\s*(\d{4}-\d{2}-\d{2})'
    match = re.search(date_pattern, search_result, re.IGNORECASE)
    if match:
        pub_date = datetime.strptime(match.group(1), '%Y-%m-%d')
        return (datetime.now() - pub_date) < timedelta(days=30)
    return False

